import React, { createContext, useContext, useState, useEffect } from 'react';
import { auth } from '../api';
import translations from '../i18n/translations';

const AppContext = createContext();

export const useApp = () => useContext(AppContext);

export const AppProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [cart, setCart] = useState([]);
  const [loading, setLoading] = useState(true);
  const [language, setLanguage] = useState(() => localStorage.getItem('lang') || 'uz');
  const [theme, setTheme] = useState(() => localStorage.getItem('theme') || 'light');
  const [notifications, setNotifications] = useState(() => {
    try {
      return JSON.parse(localStorage.getItem('notifications')) || { orders: true, offers: true, news: false };
    } catch {
      return { orders: true, offers: true, news: false };
    }
  });

  const t = translations[language] || translations.uz;

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      auth.me()
        .then(res => setUser(res.data))
        .catch(() => localStorage.removeItem('token'))
        .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, []);

  // Apply theme
  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  // Save language
  useEffect(() => {
    localStorage.setItem('lang', language);
  }, [language]);

  const login = async (username, password) => {
    const res = await auth.login(username, password);
    localStorage.setItem('token', res.data.token);
    setUser(res.data.user);
  };

  const register = async (username, email, password) => {
    await auth.register(username, email, password);
    await login(username, password);
  };

  const logout = () => {
    localStorage.removeItem('token');
    setUser(null);
  };

  const addToCart = (product, selectedColor, selectedSize) => {
    const variant = `${selectedColor}-${selectedSize}`;
    setCart(prev => {
      const existIndex = prev.findIndex(item => item.id === product.id && item.selectedColor === selectedColor && item.selectedSize === selectedSize);
      if (existIndex > -1) {
        return prev.map((item, index) => index === existIndex ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, selectedColor, selectedSize, variant, quantity: 1 }];
    });
  };

  const removeFromCart = (id, variant) => {
    setCart(prev => prev.filter(item => !(item.id === id && item.variant === variant)));
  };

  const updateQuantity = (id, variant, quantity) => {
    if (quantity < 1) return;
    setCart(prev => prev.map(item => item.id === id && item.variant === variant ? { ...item, quantity } : item));
  };

  const clearCart = () => setCart([]);

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  const updateNotifications = (key, value) => {
    const updated = { ...notifications, [key]: value };
    setNotifications(updated);
    localStorage.setItem('notifications', JSON.stringify(updated));
  };

  const cartTotal = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);
  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <AppContext.Provider value={{
      user, setUser, login, register, logout,
      cart, addToCart, removeFromCart, updateQuantity, clearCart, cartTotal, cartCount, loading,
      language, setLanguage, t,
      theme, toggleTheme,
      notifications, updateNotifications
    }}>
      {children}
    </AppContext.Provider>
  );
};
